const input = $input.first().json;
const webhook = $('Webhook').first().json;
try {
  let content = input.choices?.[0]?.message?.content || '{}';
  content = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const data = JSON.parse(content);
  return [{ json: { success: true, spoke: { slug: webhook.slug, name: webhook.name, category: webhook.category, ...data }, model: input.model } }];
} catch(e) {
  return [{ json: { success: true, spoke: { slug: webhook.slug, name: webhook.name, category: webhook.category, ai_description: input.choices?.[0]?.message?.content || 'Content generation failed', setup_steps: [], actions: [], common_errors: [], use_cases: [], code_examples: [] }, model: input.model } }];
}
